+                    ),
+                    seq: Some(record.event.seq),
+                    object_id: Some(record.object_id.to_string()),
+                });
+            }
+            None => {
+                issues.push(AuditVerifyIssue {
+                    code: "audit.object_id_unverifiable".to_string(),
